/**
 * @summary Get merchant orders for kanban view
 */
export const getGetDashboardOrdersUrl = (params?: GetDashboardOrdersParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/dashboard/orders?${stringifiedParams}`
    : `/dashboard/orders`;
};

export const getDashboardOrders = async (
  params?: GetDashboardOrdersParams,
  options?: RequestInit,
): Promise<Order[]> => {
  return customFetch<Order[]>(getGetDashboardOrdersUrl(params), {
    ...options,
    method: "GET",
  });
};

